query:
SELECT COUNT(*) as total_kpi_targets FROM kpi_targets;
SELECT COUNT(DISTINCT branchId) as branch_count FROM kpi_targets;
SELECT dimension, COUNT(*) as count FROM kpi_targets GROUP BY dimension;
SELECT b.name, COUNT(kt.id) as target_count FROM branches b LEFT JOIN kpi_targets kt ON b.id = kt.branchId GROUP BY b.id, b.name ORDER BY target_count DESC LIMIT 10;

